const body = $input.first().json.body || $input.first().json;

// Ignora mensagens enviadas por nós
if (body.fromMe === true) return [];

const phone = (body.phone || '').replace(/[^0-9]/g, '');
const texto = ((body.text && body.text.message) || body.message || '').toLowerCase().trim();

// Palavras que indicam resposta positiva
const positivo = /\b(sim|gostei|amei|adorei|show|[oó]timo|massa|top|perfeito|bo[am]|legal|curti|gostou|incrí?vel|muito bom|demais|excelente|sensacional|maravilhoso|incrivel)\b/i;
const negativo = /\b(n[aã]o|nao|nem|nope)\b/i;

const ehPositivo = positivo.test(texto) && !negativo.test(texto);

if (!phone || !ehPositivo) return [];

return [{ json: { phone, texto } }];
